int maxDepth(Node* node) {
    if (node == nullptr) {
        return 0;
    } else {
        // Compute the depth of each subtree
        int leftDepth = maxDepth(node->left);
        int rightDepth = maxDepth(node->right);

        // Use the larger one
        return std::max(leftDepth, rightDepth) + 1;
    }
}

