int lengthOfLongestSubstring(std::string s) {
    std::vector<int> m(256, -1);
    int left = 0, res = 0;
    for (int i = 0; i < s.length(); i++) {
        left = std::max(left, m[s[i]] + 1);
        res = std::max(res, i - left + 1);
        m[s[i]] = i;
    }
    return res;
}

