template <typename T, size_t S>
class CircularBuffer {
    T buffer[S];
    size_t head = 0, tail = 0;
    bool full = false;
public:
    void put(T item) {
        buffer[head] = item;
        if (full) tail = (tail + 1) % S;
        head = (head + 1) % S;
        full = head == tail;
    }
    T get() {
        if (head == tail && !full) return T();
        T val = buffer[tail];
        full = false;
        tail = (tail + 1) % S;
        return val;
    }
};

