struct Item { int val, wt; };
double knapsack(int W, std::vector<Item>& items) {
    std::sort(items.begin(), items.end(), [](Item a, Item b) {
        return (double)a.val/a.wt > (double)b.val/b.wt;
    });
    double res = 0.0;
    for (auto& i : items) {
        if (W >= i.wt) { res += i.val; W -= i.wt; }
