int quickSelect(int a[], int l, int r, int k) {
    if (k > 0 && k <= r - l + 1) {
        int index = partition(a, l, r);
        if (index - l == k - 1) return a[index];
        if (index - l > k - 1) return quickSelect(a, l, index - 1, k);
        return quickSelect(a, index + 1, r, k - index + l - 1);
    }
    return -1;
}

