public int trap(int[] height) {
    int l = 0, r = height.length - 1, lMax = 0, rMax = 0, res = 0;
    while (l < r) {
        if (height[l] < height[r]) {
            if (height[l] >= lMax) lMax = height[l];
            else res += lMax - height[l];
            l++;
        } else {
