public class CircularBuffer {
    private int[] buffer;
    private int head = 0, tail = 0, size = 0, capacity;
    public CircularBuffer(int cap) { this.capacity = cap; buffer = new int[cap]; }
    public void add(int val) {
        buffer[tail] = val;
        tail = (tail + 1) % capacity;
        if (size < capacity) size++; else head = (head + 1) % capacity;
    }
    public int poll() {
        if (size == 0) return -1;
        int val = buffer[head];
        head = (head + 1) % capacity; size--;
        return val;
    }
}

