def knapsack(wt, val, W, n, memo=None):
    if memo is None: memo = {}
    if n == 0 or W == 0: return 0
    if (n, W) in memo: return memo[(n, W)]
    if wt[n-1] > W: res = knapsack(wt, val, W, n-1, memo)
    else: res = max(val[n-1] + knapsack(wt, val, W-wt[n-1], n-1, memo), knapsack(wt, val, W, n-1, memo))
    memo[(n, W)] = res
    return res

class DSU {
    std::vector<int> parent, rank;
public:
    DSU(int n) {
        parent.resize(n); rank.resize(n, 0);
        for(int i=0; i<n; i++) parent[i] = i;
    }
    int find(int i) {
        if (parent[i] == i) return i;
        return parent[i] = find(parent[i]);
    }
    void unite(int i, int j) {
        int root_i = find(i), root_j = find(j);
        if (root_i != root_j) {
            if (rank[root_i] < rank[root_j]) parent[root_i] = root_j;
            else if (rank[root_i] > rank[root_j]) parent[root_j] = root_i;
            else { parent[root_i] = root_j; rank[root_j]++; }
        }
    }
};

