std::string manachers(std::string s) {
    std::string t = "#"; for(char c : s) { t += c; t += "#"; }
    int n = t.size(); std::vector<int> p(n, 0);
    int c = 0, r = 0, max_len = 0, center_idx = 0;
    for(int i=0; i<n; i++) {
        int mirror = 2*c - i;
        if(i < r) p[i] = std::min(r - i, p[mirror]);
        while(i + (1 + p[i]) < n && i - (1 + p[i]) >= 0 && t[i + 1 + p[i]] == t[i - 1 - p[i]]) p[i]++;
        if(i + p[i] > r) { c = i; r = i + p[i]; }
        if(p[i] > max_len) { max_len = p[i]; center_idx = i; }
    }
    return s.substr((center_idx - max_len)/2, max_len);
}

def count_inversions(arr):
    def merge_and_count(l, r):
        if l >= r: return 0
        m = (l + r) // 2
        cnt = merge_and_count(l, m) + merge_and_count(m + 1, r)
        i, j, temp = l, m + 1, []
        while i <= m and j <= r:
            if arr[i] <= arr[j]: temp.append(arr[i]); i += 1
            else: temp.append(arr[j]); j += 1; cnt += (m - i + 1)
        temp.extend(arr[i:m+1]); temp.extend(arr[j:r+1])
        arr[l:r+1] = temp
        return cnt
    return merge_and_count(0, len(arr) - 1)

