private void backtrack(TreeNode node, int sum, List<Integer> tmp, List<List<Integer>> res) {
    if (node == null) return;
    tmp.add(node.val);
    if (node.left == null && node.right == null && sum == node.val) res.add(new ArrayList<>(tmp));
    backtrack(node.left, sum - node.val, tmp, res);
    backtrack(node.right, sum - node.val, tmp, res);
    tmp.remove(tmp.size() - 1);
}

