        if (curr.child != null) {
            Node next = curr.next, child = flatten(curr.child);
            curr.next = child; child.prev = curr; curr.child = null;
            Node tail = child; while (tail.next != null) tail = tail.next;
            tail.next = next; if (next != null) next.prev = tail;
        }
        curr = curr.next;
    }
    return head;
}

