public ListNode reverseBetween(ListNode head, int m, int n) {
    ListNode dummy = new ListNode(0); dummy.next = head;
    ListNode pre = dummy; for (int i = 0; i < m - 1; i++) pre = pre.next;
    ListNode start = pre.next, then = start.next;
