void dfs(std::vector<std::vector<int>>& grid, int r, int c, std::queue<std::pair<int, int>>& q) {
    if (r < 0 || c < 0 || r >= grid.size() || c >= grid[0].size() || grid[r][c] != 1) return;
    grid[r][c] = 2;
    q.push({r, c});
    dfs(grid, r + 1, c, q); dfs(grid, r - 1, c, q);
    dfs(grid, r, c + 1, q); dfs(grid, r, c - 1, q);
}

int shortestBridge(std::vector<std::vector<int>>& grid) {
    int n = grid.size();
    std::queue<std::pair<int, int>> q;
    bool found = false;
    for (int i = 0; i < n && !found; i++) {
        for (int j = 0; j < n && !found; j++) {
            if (grid[i][j] == 1) { dfs(grid, i, j, q); found = true; }
        }
    }
    int steps = 0;
    std::vector<int> dr = {0, 0, 1, -1}, dc = {1, -1, 0, 0};
    while (!q.empty()) {
        int size = q.size();
        while (size--) {
            auto [r, c] = q.front(); q.pop();
            for (int i = 0; i < 4; i++) {
                int nr = r + dr[i], nc = c + dc[i];
                if (nr >= 0 && nc >= 0 && nr < n && nc < n) {
                    if (grid[nr][nc] == 1) return steps;
                    if (grid[nr][nc] == 0) { grid[nr][nc] = 2; q.push({nr, nc}); }
                }
            }
        }
        steps++;
    }
    return steps;
}

