std::vector<int> computeLPS(std::string pat) {
    int m = pat.length();
    std::vector<int> lps(m, 0);
    int len = 0, i = 1;
    while (i < m) {
        if (pat[i] == pat[len]) { lps[i++] = ++len; }
        else if (len != 0) { len = lps[len - 1]; }
        else { lps[i++] = 0; }
    }
    return lps;
}

int KMP(std::string txt, std::string pat) {
    std::vector<int> lps = computeLPS(pat);
    int i = 0, j = 0, n = txt.length(), m = pat.length();
    while (i < n) {
        if (pat[j] == txt[i]) { i++; j++; }
        if (j == m) return i - j;
        else if (i < n && pat[j] != txt[i]) {
            if (j != 0) j = lps[j - 1];
            else i++;
        }
    }
    return -1;
}

public boolean isStronglyConnected(int n, List<Integer>[] adj) {
    boolean[] visited = new boolean[n];
    dfs(0, adj, visited);
    for (boolean v : visited) if (!v) return false;

    List<Integer>[] revAdj = new ArrayList[n];
    for (int i = 0; i < n; i++) revAdj[i] = new ArrayList<>();
    for (int i = 0; i < n; i++) for (int neighbor : adj[i]) revAdj[neighbor].add(i);

    Arrays.fill(visited, false);
    dfs(0, revAdj, visited);
    for (boolean v : visited) if (!v) return false;
    return true;
}
