def topo_sort(n, adj):
    in_degree = [0] * n
    for u in adj: 
        for v in adj[u]: in_degree[v] += 1
    q = deque([i for i in range(n) if in_degree[i] == 0])
    res = []
    while q:
        u = q.popleft(); res.append(u)
        for v in adj[u]:
            in_degree[v] -= 1
            if in_degree[v] == 0: q.append(v)
    return res if len(res) == n else []

