void findAP(int u, int p, int& timer, std::vector<int> adj[], std::vector<int>& tin, 
            std::vector<int>& low, std::vector<bool>& ap) {
    tin[u] = low[u] = ++timer;
    int children = 0;
    for (int v : adj[u]) {
        if (v == p) continue;
        if (tin[v]) {
            low[u] = std::min(low[u], tin[v]);
        } else {
            findAP(v, u, timer, adj, tin, low, ap);
            low[u] = std::min(low[u], low[v]);
            if (low[v] >= tin[u] && p != -1) ap[u] = true;
            ++children;
        }
    }
    if (p == -1 && children > 1) ap[u] = true;
}

