}

class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end = False

class Trie:
    def __init__(self):
        self.root = TrieNode()
    def insert(self, word):
        curr = self.root
        for char in word:
            if char not in curr.children: curr.children[char] = TrieNode()
            curr = curr.children[char]
        curr.is_end = True
    def search(self, word):
        curr = self.root
        for char in word:
            if char not in curr.children: return False
            curr = curr.children[char]
