std::vector<int> shortestPath(int n, std::vector<int> adj[], int src, int dest) {
    std::vector<int> parent(n, -1);
    std::queue<int> q; q.push(src);
    while(!q.empty()) {
        int u = q.front(); q.pop();
        if (u == dest) break;
        for (int v : adj[u]) {
            if (parent[v] == -1 && v != src) {
                parent[v] = u;
                q.push(v);
            }
        }
    }
    std::vector<int> path;
    for (int v = dest; v != -1; v = parent[v]) path.push_back(v);
    std::reverse(path.begin(), path.end());
    return path;
}

