public int kthSmallest(int[][] matrix, int k) {
    int n = matrix.length;
    int lo = matrix[0][0], hi = matrix[n - 1][n - 1];
    while (lo < hi) {
        int mid = lo + (hi - lo) / 2;
        int count = countLessEqual(matrix, mid);
        if (count < k) lo = mid + 1;
        else hi = mid;
    }
    return lo;
}
private int countLessEqual(int[][] matrix, int val) {
    int count = 0, n = matrix.length, r = n - 1, c = 0;
    while (r >= 0 && c < n) {
        if (matrix[r][c] <= val) { count += r + 1; c++; }
        else r--;
    }
    return count;
}

