def solveSudoku(board):
    def is_valid(r, c, val):
        for i in range(9):
            if board[r][i] == val or board[i][c] == val or \
               board[3*(r//3)+i//3][3*(c//3)+i%3] == val: return False
        return True
    def backtrack():
        for r in range(9):
            for c in range(9):
                if board[r][c] == '.':
                    for val in '123456789':
                        if is_valid(r, c, val):
                            board[r][c] = val
                            if backtrack(): return True
                            board[r][c] = '.'
                    return False
        return True
    backtrack()

