int ladderLength(std::string begin, std::string end, std::vector<std::string>& dict) {
    std::unordered_set<std::string> s(dict.begin(), dict.end());
    std::queue<std::pair<std::string, int>> q; q.push({begin, 1});
    while (!q.empty()) {
        auto [word, dist] = q.front(); q.pop();
        if (word == end) return dist;
        for (int i = 0; i < word.size(); i++) {
            char original = word[i];
            for (char c = 'a'; c <= 'z'; c++) {
                word[i] = c;
                if (s.count(word)) { s.erase(word); q.push({word, dist + 1}); }
            }
            word[i] = original;
        }
    }
    return 0;
}

