std::string longestPalindrome(std::string s) {
    std::string t = "#";
    for (char c : s) { t += c; t += "#"; }
    int n = t.size();
    std::vector<int> p(n, 0);
    int c = 0, r = 0, maxLen = 0, center = 0;
    for (int i = 0; i < n; i++) {
        int mirror = 2 * c - i;
        if (i < r) p[i] = std::min(r - i, p[mirror]);
        while (i + 1 + p[i] < n && i - 1 - p[i] >= 0 && t[i + 1 + p[i]] == t[i - 1 - p[i]]) p[i]++;
        if (i + p[i] > r) { c = i; r = i + p[i]; }
        if (p[i] > maxLen) { maxLen = p[i]; center = i; }
    }
    return s.substr((center - maxLen) / 2, maxLen);
}

public boolean isTree(int n, int[][] edges) {
    if (edges.length != n - 1) return false;
    List<Integer>[] adj = new ArrayList[n];
    for (int i = 0; i < n; i++) adj[i] = new ArrayList<>();
    for (int[] e : edges) { adj[e[0]].add(e[1]); adj[e[1]].add(e[0]); }
    boolean[] visited = new boolean[n];
    if (hasCycle(0, -1, adj, visited)) return false;
    for (boolean v : visited) if (!v) return false;
    return true;
}
private boolean hasCycle(int u, int p, List<Integer>[] adj, boolean[] visited) {
    visited[u] = true;
    for (int v : adj[u]) {
        if (!visited[v]) { if (hasCycle(v, u, adj, visited)) return true; }
        else if (v != p) return true;
    }
    return false;
}

