        update(rank[n])
    return res[::-1]

public List<List<Integer>> zigzagLevelOrder(TreeNode root) {
    List<List<Integer>> res = new ArrayList<>();
    if (root == null) return res;
    Stack<TreeNode> s1 = new Stack<>(), s2 = new Stack<>();
    s1.push(root);
    while (!s1.isEmpty() || !s2.isEmpty()) {
        List<Integer> level = new ArrayList<>();
        while (!s1.isEmpty()) {
            TreeNode n = s1.pop(); level.add(n.val);
            if (n.left != null) s2.push(n.left); if (n.right != null) s2.push(n.right);
        }
        if (!level.isEmpty()) res.add(level);
        level = new ArrayList<>();
        while (!s2.isEmpty()) {
            TreeNode n = s2.pop(); level.add(n.val);
            if (n.right != null) s1.push(n.right); if (n.left != null) s1.push(n.left);
        }
        if (!level.isEmpty()) res.add(level);
    }
    return res;
}

int maxCoins(std::vector<int>& nums) {
    nums.insert(nums.begin(), 1); nums.push_back(1);
    int n = nums.size();
    std::vector<std::vector<int>> dp(n, std::vector<int>(n, 0));
    for (int len = 2; len < n; len++) {
        for (int left = 0; left < n - len; left++) {
            int right = left + len;
            for (int k = left + 1; k < right; k++) {
                dp[left][right] = std::max(dp[left][right], nums[left] * nums[k] * nums[right] + dp[left][k] + dp[k][right]);
            }
        }
    }
    return dp[0][n - 1];
}

function solveNQueens(n) {
    const board = Array.from({length: n}, () => Array(n).fill('.'));
    function isValid(r, c) {
        for (let i = 0; i < r; i++) {
            if (board[i][c] === 'Q') return false;
            const diag1 = c - (r - i), diag2 = c + (r - i);
            if (diag1 >= 0 && board[i][diag1] === 'Q') return false;
            if (diag2 < n && board[i][diag2] === 'Q') return false;
        }
        return true;
    }
    function backtrack(r) {
        if (r === n) return true;
        for (let c = 0; c < n; c++) {
            if (isValid(r, c)) {
                board[r][c] = 'Q';
                if (backtrack(r + 1)) return true;
                board[r][c] = '.';
            }
        }
        return false;
    }
    backtrack(0);
    return board.map(row => row.join(''));
}

