public List<Integer> distanceK(TreeNode root, TreeNode target, int k) {
    findParents(root, null);
    Queue<TreeNode> q = new LinkedList<>(); q.add(target);
    Set<TreeNode> vis = new HashSet<>(); vis.add(target);
    int dist = 0;
    while (!q.isEmpty()) {
        if (dist == k) {
            List<Integer> res = new ArrayList<>();
            for (TreeNode n : q) res.add(n.val); return res;
        }
        int size = q.size();
        for (int i = 0; i < size; i++) {
            TreeNode n = q.poll();
            TreeNode[] next = {n.left, n.right, parent.get(n)};
            for (TreeNode v : next) if (v != null && vis.add(v)) q.add(v);
        }
        dist++;
    }
    return new ArrayList<>();
}
