def trapRainWater(grid):
    R, C = len(grid), len(grid[0])
    vis = [[False] * C for _ in range(R)]
    pq = []
    for r in range(R): 
        for c in [0, C-1]: heapq.heappush(pq, (grid[r][c], r, c)); vis[r][c] = True
    for c in range(1, C-1): 
        for r in [0, R-1]: heapq.heappush(pq, (grid[r][c], r, c)); vis[r][c] = True
    res = 0
    while pq:
        h, r, c = heapq.heappop(pq)
        for dr, dc in [(0,1),(0,-1),(1,0),(-1,0)]:
