void tarjan(int u, std::vector<int> adj[], std::vector<int>& dfn, std::vector<int>& low, std::stack<int>& st, std::vector<bool>& inSt, int& timer) {
    dfn[u] = low[u] = ++timer; st.push(u); inSt[u] = true;
    for (int v : adj[u]) {
        if (!dfn[v]) {
            tarjan(v, adj, dfn, low, st, inSt, timer);
            low[u] = std::min(low[u], low[v]);
        } else if (inSt[v]) low[u] = std::min(low[u], dfn[v]);
    }
    if (low[u] == dfn[u]) {
        while (true) {
            int node = st.top(); st.pop(); inSt[node] = false;
            if (node == u) break;
        }
    }
}

