class AutocompleteSystem:
    def __init__(self, sentences, times):
        self.trie = {}; self.data = ""
        for s, t in zip(sentences, times): self.add(s, t)
    def add(self, s, t):
        node = self.trie
        for c in s:
            if c not in node: node[c] = {"#": {}}
            node = node[c]; node["#"][s] = node["#"].get(s, 0) + t
    def input(self, c):
        if c == "#": self.add(self.data, 1); self.data = ""; return []
        self.data += c; node = self.trie
        for char in self.data:
            if char not in node: return []
            node = node[char]
        res = [(-v, k) for k, v in node["#"].items()]
        heapq.heapify(res)
        return [heapq.heappop(res)[1] for _ in range(min(3, len(res)))]

