function mergeKLists(lists) {
    const heap = new MinHeap((a, b) => a.val < b.val);
    lists.forEach(l => l && heap.push(l));
    const dummy = new ListNode(0);
    let curr = dummy;
    while (!heap.isEmpty()) {
        const node = heap.pop();
        curr.next = node; curr = curr.next;
        if (node.next) heap.push(node.next);
    }
    return dummy.next;
}

