def mincostToHireWorkers(quality, wage, k):
    workers = sorted([w/q, q] for q, w in zip(quality, wage))
    res = float('inf'); qsum = 0; h = []
    for r, q in workers:
        heapq.heappush(h, -q); qsum += q
        if len(h) > k: qsum += heapq.heappop(h)
        if len(h) == k: res = min(res, r * qsum)
    return res

void dfs(int u, int p, int& timer, std::vector<int> adj[], std::vector<int>& tin, std::vector<int>& low, std::vector<std::vector<int>>& res) {
    tin[u] = low[u] = timer++;
    for (int v : adj[u]) {
        if (v == p) continue;
        if (tin[v] == -1) {
            dfs(v, u, timer, adj, tin, low, res);
            low[u] = std::min(low[u], low[v]);
            if (low[v] > tin[u]) res.push_back({u, v});
        } else low[u] = std::min(low[u], tin[v]);
    }
}

function combinationSum3(k, n) {
    const res = [];
    function backtrack(start, target, path) {
        if (path.length === k) {
            if (target === 0) res.push([...path]); return;
        }
        for (let i = start; i <= 9; i++) {
            if (i > target) break;
            backtrack(i + 1, target - i, [...path, i]);
        }
    }
    backtrack(1, n, []); return res;
}

public String findSmallestRegion(List<List<String>> regions, String r1, String r2) {
    Map<String, String> parents = new HashMap<>();
    for (List<String> r : regions) for (int i = 1; i < r.size(); i++) parents.put(r.get(i), r.get(0));
    Set<String> path = new HashSet<>();
    while (r1 != null) { path.add(r1); r1 = parents.get(r1); }
    while (!path.contains(r2)) r2 = parents.get(r2); return r2;
}

int height(TreeNode* n) {
    if (!n) return 0;
    int l = height(n->left); if (l == -1) return -1;
    int r = height(n->right); if (r == -1) return -1;
    return abs(l - r) > 1 ? -1 : 1 + std::max(l, r);
}
bool isBalanced(TreeNode* root) { return height(root) != -1; }

def countUnivalSubtrees(root):
    self.res = 0
    def is_uni(node):
        if not node: return True
        left, right = is_uni(node.left), is_uni(node.right)
        if left and right and (not node.left or node.left.val == node.val) and (not node.right or node.right.val == node.val):
            self.res += 1; return True
        return False
    is_uni(root); return self.res

std::vector<int> findAnagrams(std::string s, std::string p) {
