    int l = 0, r = 0, diff = p.size();
    while (r < s.size()) {
        if (cnt[s[r++] - 'a']-- > 0) diff--;
        if (diff == 0) res.add(l);
        if (r - l == p.size() && cnt[s[l++] - 'a']++ >= 0) diff++;
