def lengthOfLongestSubstringKDistinct(s, k):
    if k == 0: return 0
    seen = {}; l = res = 0
    for r, c in enumerate(s):
        seen[c] = r
        if len(seen) > k:
            min_idx = min(seen.values())
            del seen[s[min_idx]]; l = min_idx + 1
        res = max(res, r - l + 1)
    return res

int minCut(std::string s) {
    int n = s.size(); std::vector<int> dp(n + 1);
    for (int i = 0; i <= n; i++) dp[i] = i - 1;
    for (int i = 0; i < n; i++) {
        for (int j = 0; i - j >= 0 && i + j < n && s[i - j] == s[i + j]; j++) dp[i + j + 1] = std::min(dp[i + j + 1], 1 + dp[i - j]);
        for (int j = 1; i - j + 1 >= 0 && i + j < n && s[i - j + 1] == s[i + j]; j++) dp[i + j + 1] = std::min(dp[i + j + 1], 1 + dp[i - j + 1]);
    }
    return dp[n];
}

def shortestWay(source, target):
    res = i = 0
    while i < len(target):
        j = source.find(target[i])
        if j == -1: return -1
        while i < len(target) and j != -1:
            i += 1; j = source.find(target[i], j + 1) if i < len(target) else -1
        res += 1
    return res

class FreqStack {
    std::unordered_map<int, int> freq;
    std::unordered_map<int, std::stack<int>> group;
    int maxFreq = 0;
public:
    void push(int x) { maxFreq = std::max(maxFreq, ++freq[x]); group[freq[x]].push(x); }
    int pop() {
        int x = group[maxFreq].top(); group[maxFreq].pop();
        freq[x]--; if (group[maxFreq].empty()) maxFreq--; return x;
    }
};

def maximalRectangle(matrix):
    if not matrix: return 0
    R, C = len(matrix), len(matrix[0]); heights = [0] * (C + 1); res = 0
    for row in matrix:
        for i in range(C): heights[i] = heights[i] + 1 if row[i] == '1' else 0
        stack = [-1]
        for i, h in enumerate(heights):
            while heights[stack[-1]] > h: res = max(res, heights[stack.pop()] * (i - stack[-1] - 1))
            stack.append(i)
    return res

ListNode* reverseBetween(ListNode* head, int m, int n) {
    ListNode dummy(0); dummy.next = head; ListNode* pre = &dummy;
    for (int i = 0; i < m - 1; i++) pre = pre->next;
    ListNode* start = pre->next; ListNode* then = start->next;
    for (int i = 0; i < n - m; i++) {
        start->next = then->next; then->next = pre->next; pre->next = then; then = start->next;
    }
    return dummy.next;
}

def isInterleave(s1, s2, s3):
    if len(s1) + len(s2) != len(s3): return False
    dp = [True] + [False] * len(s2)
    for j in range(1, len(s2) + 1): dp[j] = dp[j-1] and s2[j-1] == s3[j-1]
    for i in range(1, len(s1) + 1):
        dp[0] = dp[0] and s1[i-1] == s3[i-1]
        for j in range(1, len(s2) + 1):
            dp[j] = (dp[j] and s1[i-1] == s3[i+j-1]) or (dp[j-1] and s2[j-1] == s3[i+j-1])
    return dp[-1]

function isBipartite(adj) {
    const colors = Array(adj.length).fill(0);
    const dfs = (u, c) => {
        colors[u] = c;
        for (let v of adj[u]) {
            if (colors[v] === c) return false;
            if (colors[v] === 0 && !dfs(v, -c)) return false;
        }
        return true;
    };
    for (let i = 0; i < adj.length; i++) if (colors[i] === 0 && !dfs(i, 1)) return false;
    return true;
}

public boolean validPalindrome(String s) {
    int l = 0, r = s.length() - 1;
    while (l < r) {
        if (s.charAt(l) != s.charAt(r)) return isPal(s, l+1, r) || isPal(s, l, r-1);
        l++; r--;
    }
    return true;
}
private boolean isPal(String s, int i, int j) { while (i < j) if (s.charAt(i++) != s.charAt(j--)) return false; return true; }

int minMeetingRooms(std::vector<std::vector<int>>& intervals) {
    if (intervals.empty()) return 0;
    std::sort(intervals.begin(), intervals.end());
    std::priority_queue<int, std::vector<int>, std::greater<int>> pq;
    pq.push(intervals[0][1]);
    for (int i = 1; i < intervals.size(); i++) {
        if (intervals[i][0] >= pq.top()) pq.pop();
        pq.push(intervals[i][1]);
    }
    return pq.size();
}

function rotate(nums, k) {
    k %= nums.length; const rev = (i, j) => {
        while (i < j) [nums[i], nums[j]] = [nums[j], nums[i]], i++, j--;
    };
    rev(0, nums.length - 1); rev(0, k - 1); rev(k, nums.length - 1);
}

