public void flatten(TreeNode root) {
    TreeNode curr = root;
    while (curr != null) {
        if (curr.left != null) {
            TreeNode pre = curr.left; while (pre.right != null) pre = pre.right;
            pre.right = curr.right; curr.right = curr.left; curr.left = null;
        }
        curr = curr.right;
    }
}

def postorder(root):
    res = []; stack = []; curr = root
    while curr or stack:
        if curr: stack.append(curr); curr = curr.left
        else:
            tmp = stack[-1].right
            if tmp: curr = tmp
            else:
                tmp = stack.pop(); res.append(tmp.val)
                while stack and tmp == stack[-1].right: tmp = stack.pop(); res.append(tmp.val)
    return res

function merge(intervals) {
    intervals.sort((a, b) => a[0] - b[0]);
    const res = [intervals[0]];
    for (let i = 1; i < intervals.length; i++) {
        if (intervals[i][0] <= res[res.length - 1][1]) res[res.length - 1][1] = Math.max(res[res.length - 1][1], intervals[i][1]);
        else res.push(intervals[i]);
    }
    return res;
}

def search(nums, target):
    l, r = 0, len(nums) - 1
    while l <= r:
        m = (l + r) // 2
        if nums[m] == target: return True
        if nums[l] == nums[m]: l += 1
        elif nums[l] < nums[m]:
            if nums[l] <= target < nums[m]: r = m - 1
            else: l = m + 1
        else:
            if nums[m] < target <= nums[r]: l = m + 1
            else: r = m - 1
    return False

bool hasPathSum(TreeNode* root, int sum) {
    if (!root) return false;
    if (!root->left && !root->right) return sum == root->val;
    return hasPathSum(root->left, sum - root->val) || hasPathSum(root->right, sum - root->val);
}

