int shortestPath(std::vector<std::vector<int>>& grid, int k) {
    int m = grid.size(), n = grid[0].size();
    std::queue<std::tuple<int, int, int, int>> q;
    q.push({0, 0, k, 0});
    std::vector<std::vector<int>> visited(m, std::vector<int>(n, -1));
    while (!q.empty()) {
        auto [r, c, rem, d] = q.front(); q.pop();
        if (r == m - 1 && c == n - 1) return d;
        int dr[] = {0, 0, 1, -1}, dc[] = {1, -1, 0, 0};
        for (int i = 0; i < 4; i++) {
            int nr = r + dr[i], nc = c + dc[i];
            if (nr >= 0 && nr < m && nc >= 0 && nc < n) {
                int next_rem = rem - grid[nr][nc];
                if (next_rem >= 0 && visited[nr][nc] < next_rem) {
                    visited[nr][nc] = next_rem;
                    q.push({nr, nc, next_rem, d + 1});
                }
            }
        }
    }
    return -1;
}

import heapq

def minCostConnectPoints(points):
    n = len(points)
    adj = {i: [] for i in range(n)}
    for i in range(n):
        x1, y1 = points[i]
        for j in range(i + 1, n):
            x2, y2 = points[j]
            dist = abs(x1 - x2) + abs(y1 - y2)
            adj[i].append([dist, j])
            adj[j].append([dist, i])
    res = 0
    visit = set()
    minH = [[0, 0]]
    while len(visit) < n:
        cost, i = heapq.heappop(minH)
        if i in visit: continue
        res += cost
        visit.add(i)
        for d, neighbor in adj[i]:
            if neighbor not in visit: heapq.heappush(minH, [d, neighbor])
    return res

public int countComponents(int n, int[][] edges) {
    int[] parent = new int[n];
    for (int i = 0; i < n; i++) parent[i] = i;
    int count = n;
    for (int[] edge : edges) {
        int root1 = find(parent, edge[0]);
        int root2 = find(parent, edge[1]);
        if (root1 != root2) {
            parent[root1] = root2;
            count--;
        }
    }
    return count;
}
private int find(int[] parent, int i) {
    if (parent[i] == i) return i;
    return parent[i] = find(parent, parent[i]);
}

void reorderList(ListNode* head) {
    if (!head || !head->next) return;
    ListNode *slow = head, *fast = head;
    while (fast && fast->next) { slow = slow->next; fast = fast->next->next; }
    ListNode *prev = nullptr, *curr = slow->next, *next = nullptr;
    slow->next = nullptr;
    while (curr) {
        next = curr->next; curr->next = prev; prev = curr; curr = next;
    }
    ListNode *l1 = head, *l2 = prev;
    while (l2) {
        ListNode *n1 = l1->next, *n2 = l2->next;
        l1->next = l2; l2->next = n1; l1 = n1; l2 = n2;
    }
}

function deepMergeConcat(target, source) {
    for (const key in source) {
        if (Array.isArray(source[key]) && Array.isArray(target[key])) {
            target[key] = [...target[key], ...source[key]];
        } else if (source[key] instanceof Object && key in target) {
            deepMergeConcat(target[key], source[key]);
        } else {
            target[key] = source[key];
        }
    }
    return target;
}

from collections import deque
def maxSlidingWindow(nums, k):
    q = deque() 
    res = []
    for i, n in enumerate(nums):
        while q and nums[q[-1]] < n: q.pop()
        q.append(i)
        if q[0] == i - k: q.popleft()
        if i >= k - 1: res.append(nums[q[0]])
    return res

void bfs(std::vector<std::vector<int>>& heights, std::queue<std::pair<int, int>>& q, std::vector<std::vector<bool>>& reachable) {
    int m = heights.size(), n = heights[0].size();
    while (!q.empty()) {
        auto [r, c] = q.front(); q.pop();
        reachable[r][c] = true;
        int dr[] = {0, 0, 1, -1}, dc[] = {1, -1, 0, 0};
        for (int i = 0; i < 4; i++) {
            int nr = r + dr[i], nc = c + dc[i];
            if (nr >= 0 && nr < m && nc >= 0 && nc < n && !reachable[nr][nc] && heights[nr][nc] >= heights[r][c]) {
                q.push({nr, nc});
            }
        }
    }
}

