int findDuplicate(std::vector<int>& nums) {
    int slow = nums[0], fast = nums[0];
    do { slow = nums[slow]; fast = nums[nums[fast]]; } while (slow != fast);
    slow = nums[0];
    while (slow != fast) { slow = nums[slow]; fast = nums[fast]; }
    return slow;
}

public int numDecodings(String s) {
    int n = s.length();
    int[] dp = new int[n + 1];
    dp[0] = 1;
    dp[1] = s.charAt(0) == '0' ? 0 : 1;
    for (int i = 2; i <= n; i++) {
        int first = Integer.valueOf(s.substring(i - 1, i));
        int second = Integer.valueOf(s.substring(i - 2, i));
        if (first >= 1 && first <= 9) dp[i] += dp[i - 1];
        if (second >= 10 && second <= 26) dp[i] += dp[i - 2];
    }
    return dp[n];
}

const exist = (board, word) => {
    const R = board.length, C = board[0].length;
    const dfs = (r, c, i) => {
        if (i === word.length) return true;
        if (r < 0 || r >= R || c < 0 || c >= C || board[r][c] !== word[i]) return false;
        const temp = board[r][c];
        board[r][c] = '#';
        const res = dfs(r+1, c, i+1) || dfs(r-1, c, i+1) || dfs(r, c+1, i+1) || dfs(r, c-1, i+1);
        board[r][c] = temp;
        return res;
    };
    for (let i = 0; i < R; i++) for (let j = 0; j < C; j++) if (dfs(i, j, 0)) return true;
    return false;
};

def canPartitionKSubsets(nums, k):
    total = sum(nums)
    if total % k != 0: return False
    target = total // k
    nums.sort(reverse=True)
    used = [False] * len(nums)
    def backtrack(i, k, curr_sum):
        if k == 0: return True
        if curr_sum == target: return backtrack(0, k - 1, 0)
        for j in range(i, len(nums)):
            if used[j] or curr_sum + nums[j] > target: continue
            used[j] = True
            if backtrack(j + 1, k, curr_sum + nums[j]): return True
            used[j] = False
        return False
    return backtrack(0, k, 0)

int search(const ArrayReader& reader, int target) {
    int left = 0, right = 1;
    while (reader.get(right) < target) { left = right; right <<= 1; }
    while (left <= right) {
        int mid = left + (right - left) / 2;
        int val = reader.get(mid);
        if (val == target) return mid;
        if (val > target) right = mid - 1;
        else left = mid + 1;
    }
    return -1;
}

public int[][] generateMatrix(int n) {
    int[][] res = new int[n][n];
    int r1 = 0, r2 = n - 1, c1 = 0, c2 = n - 1, val = 1;
    while (r1 <= r2 && c1 <= c2) {
        for (int i = c1; i <= c2; i++) res[r1][i] = val++;
        for (int i = r1 + 1; i <= r2; i++) res[i][c2] = val++;
        if (r1 < r2 && c1 < c2) {
            for (int i = c2 - 1; i > c1; i--) res[r2][i] = val++;
            for (int i = r2; i > r1; i--) res[i][c1] = val++;
        }
        r1++; r2--; c1++; c2--;
    }
    return res;
}

