    res = []
    def dfs(r, c, node):
        char = board[r][c]
        curr = node[char]
        word = curr.pop('#', None)
        if word: res.append(word)
        board[r][c] = '*'
        for dr, dc in [(0,1),(0,-1),(1,0),(-1,0)]:
            nr, nc = r+dr, c+dc
            if 0<=nr<len(board) and 0<=nc<len(board[0]) and board[nr][nc] in curr:
                dfs(nr, nc, curr)
        board[r][c] = char
        if not curr: node.pop(char)
    for i in range(len(board)): 
        for j in range(len(board[0])): 
            if board[i][j] in trie: dfs(i, j, trie)
    return res

