const calculateMinimumHP = (dungeon) => {
    const R = dungeon.length, C = dungeon[0].length;
    const dp = Array.from({length: R + 1}, () => Array(C + 1).fill(Infinity));
    dp[R][C-1] = dp[R-1][C] = 1;
    for (let r = R - 1; r >= 0; r--) {
        for (let c = C - 1; c >= 0; c--) {
            let need = Math.min(dp[r+1][c], dp[r][c+1]) - dungeon[r][c];
            dp[r][c] = need <= 0 ? 1 : need;
        }
    }
    return dp[0][0];
};

