def countRangeSum(nums, lower, upper):
    prefix = [0]
    for n in nums: prefix.append(prefix[-1] + n)
    def merge_sort(l, r):
        if l >= r: return 0
        mid = (l + r) // 2
        cnt = merge_sort(l, mid) + merge_sort(mid + 1, r)
        i, j = mid + 1, mid + 1
        for left in prefix[l:mid+1]:
            while i <= r and prefix[i] - left < lower: i += 1
            while j <= r and prefix[j] - left <= upper: j += 1
            cnt += j - i
        prefix[l:r+1] = sorted(prefix[l:r+1])
        return cnt
    return merge_sort(0, len(prefix) - 1)

void reorderList(ListNode* head) {
    if (!head || !head->next) return;
    ListNode *slow = head, *fast = head;
    while (fast && fast->next) { slow = slow->next; fast = fast->next->next; }
    ListNode *prev = nullptr, *curr = slow->next, *tmp; slow->next = nullptr;
    while (curr) { tmp = curr->next; curr->next = prev; prev = curr; curr = tmp; }
    ListNode *n1 = head, *n2 = prev;
    while (n2) { ListNode *t1 = n1->next, *t2 = n2->next; n1->next = n2; n2->next = t1; n1 = t1; n2 = t2; }
}

