def canFinish(n, pre):
    adj = [[] for _ in range(n)]
    for v, u in pre: adj[u].append(v)
    vis = [0] * n # 0=none, 1=visiting, 2=visited
    def cycle(u):
        if vis[u] == 1: return True
        if vis[u] == 2: return False
        vis[u] = 1
        for v in adj[u]:
            if cycle(v): return True
        vis[u] = 2; return False
    return all(not cycle(i) for i in range(n))

std::vector<std::vector<std::string>> groupAnagrams(std::vector<std::string>& strs) {
    std::unordered_map<std::string, std::vector<std::string>> map;
    for (auto& s : strs) {
        std::string t = s; std::sort(t.begin(), t.end());
        map[t].push_back(s);
    }
    std::vector<std::vector<std::string>> res;
    for (auto& p : map) res.push_back(p.second);
    return res;
}

public boolean isAnagram(String s, String t) {
    if (s.length() != t.length()) return false;
    int[] cnt = new int[26];
    for (char c : s.toCharArray()) cnt[c - 'a']++;
    for (char c : t.toCharArray()) if (--cnt[c - 'a'] < 0) return false;
    return true;
}

