def numIslands(grid):
    if not grid: return 0
    R, C, res = len(grid), len(grid[0]), 0
    def dfs(r, c):
        if r<0 or r>=R or c<0 or c>=C or grid[r][c] == '0': return
        grid[r][c] = '0'
        for dr, dc in [(0,1),(0,-1),(1,0),(-1,0)]: dfs(r+dr, c+dc)
    for r in range(R):
        for c in range(C):
            if grid[r][c] == '1': res += 1; dfs(r, c)
    return res

