from collections import deque
def levelOrder(root):
    if not root: return []
    res, q = [], deque([root])
    while q:
        level = []
        for _ in range(len(q)):
            n = q.popleft(); level.append(n.val)
            if n.left: q.append(n.left)
            if n.right: q.append(n.right)
        res.append(level)
    return res

std::vector<int> preorderTraversal(TreeNode* root) {
    if (!root) return {};
    std::vector<int> res; std::stack<TreeNode*> s; s.push(root);
    while (!s.empty()) {
        TreeNode* n = s.top(); s.pop(); res.push_back(n->val);
        if (n->right) s.push(n->right); if (n->left) s.push(n->left);
    }
    return res;
}

public ListNode reverseList(ListNode head) {
    ListNode prev = null, curr = head;
    while (curr != null) {
        ListNode next = curr.next; curr.next = prev;
        prev = curr; curr = next;
    }
    return prev;
}

const search = (nums, target) => {
    let l = 0, r = nums.length - 1;
    while (l <= r) {
        let m = Math.floor((l + r) / 2);
        if (nums[m] === target) return m;
        if (nums[m] < target) l = m + 1; else r = m - 1;
    }
    return -1;
};

def isValid(s):
    stack, map = [], {")": "(", "}": "{", "]": "["}
    for c in s:
        if c in map:
            if not stack or stack.pop() != map[c]: return False
        else: stack.append(c)
    return not stack

std::vector<int> inorderTraversal(TreeNode* root) {
    std::vector<int> res; std::stack<TreeNode*> s; TreeNode* curr = root;
    while (curr || !s.empty()) {
        while (curr) { s.push(curr); curr = curr->left; }
        curr = s.top(); s.pop(); res.push_back(curr->val); curr = curr->right;
    }
    return res;
}

