const mergeTwoLists = (l1, l2) => {
    if (!l1) return l2; if (!l2) return l1;
    if (l1.val < l2.val) { l1.next = mergeTwoLists(l1.next, l2); return l1; }
    else { l2.next = mergeTwoLists(l1, l2.next); return l2; }
};

def asteroidCollision(asteroids):
    stack = []
    for a in asteroids:
        while stack and a < 0 < stack[-1]:
            if stack[-1] < -a:
                stack.pop()
                continue
            elif stack[-1] == -a:
                stack.pop()
            break
        else:
            stack.append(a)
    return stack

public int lenLongestFibSubseq(int[] arr) {
    int n = arr.length, maxLen = 0;
    Map<Integer, Integer> index = new HashMap<>();
    for (int i = 0; i < n; i++) index.put(arr[i], i);
    Map<Integer, Integer> dp = new HashMap<>();
    for (int k = 0; k < n; k++) {
        for (int j = 0; j < k; j++) {
            int i = index.getOrDefault(arr[k] - arr[j], -1);
            if (i >= 0 && i < j) {
                int len = dp.getOrDefault(i * n + j, 2) + 1;
                dp.put(j * n + k, len);
                maxLen = Math.max(maxLen, len);
            }
        }
    }
    return maxLen >= 3 ? maxLen : 0;
}

int numIslands(std::vector<std::vector<char>>& grid) {
    int m = grid.size(), n = grid[0].size(), count = 0;
    int dr[] = {0, 0, 1, -1}, dc[] = {1, -1, 0, 0};
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            if (grid[i][j] == '1') {
                count++;
                std::queue<std::pair<int, int>> q;
                q.push({i, j}); grid[i][j] = '0';
                while (!q.empty()) {
                    auto [r, c] = q.front(); q.pop();
                    for (int k = 0; k < 4; k++) {
                        int nr = r + dr[k], nc = c + dc[k];
                        if (nr >= 0 && nr < m && nc >= 0 && nc < n && grid[nr][nc] == '1') {
                            grid[nr][nc] = '0'; q.push({nr, nc});
                        }
                    }
                }
            }
        }
    }
    return count;
}

const partitionLabels = (s) => {
    const last = {};
    for (let i = 0; i < s.length; i++) last[s[i]] = i;
    let res = [], start = 0, end = 0;
    for (let i = 0; i < s.length; i++) {
        end = Math.max(end, last[s[i]]);
        if (i === end) {
            res.push(i - start + 1);
            start = i + 1;
        }
    }
    return res;
};

public List<List<Integer>> subsetsWithDup(int[] nums) {
    Arrays.sort(nums);
    List<List<Integer>> res = new ArrayList<>();
    backtrack(res, new ArrayList<>(), nums, 0);
    return res;
}
private void backtrack(List<List<Integer>> res, List<Integer> tmp, int[] nums, int start) {
    res.add(new ArrayList<>(tmp));
    for (int i = start; i < nums.length; i++) {
        if (i > start && nums[i] == nums[i-1]) continue;
        tmp.add(nums[i]);
        backtrack(res, tmp, nums, i + 1);
        tmp.remove(tmp.size() - 1);
    }
}

int leastInterval(std::vector<char>& tasks, int n) {
    std::vector<int> freq(26, 0);
    for (char t : tasks) freq[t - 'A']++;
    std::sort(freq.begin(), freq.end());
    int max_f = freq[23] - 1;
    int idle = max_f * n;
    for (int i = 24; i >= 0 && freq[i] > 0; i--) idle -= std::min(freq[i], max_f);
    return idle > 0 ? idle + tasks.size() : tasks.size();
}

const widthOfBinaryTree = (root) => {
    if (!root) return 0;
    let maxW = 0, q = [{node: root, id: 0n}];
    while (q.length) {
        let size = q.length, start = q[0].id, end = q[size - 1].id;
        maxW = Math.max(maxW, Number(end - start + 1n));
        let nextQ = [];
        for (let {node, id} of q) {
            if (node.left) nextQ.push({node: node.left, id: id * 2n});
            if (node.right) nextQ.push({node: node.right, id: id * 2n + 1n});
        }
        q = nextQ;
    }
    return maxW;
};

def countAndSay(n):
