public String validIPAddress(String IP) {
    if (IP.chars().filter(ch -> ch == '.').count() == 3) return validIPv4(IP);
    if (IP.chars().filter(ch -> ch == ':').count() == 7) return validIPv6(IP);
    return "Neither";
}
private String validIPv4(String IP) {
    String[] nums = IP.split("\\.", -1);
    for (String x : nums) {
        if (x.length() == 0 || x.length() > 3) return "Neither";
        if (x.charAt(0) == '0' && x.length() != 1) return "Neither";
        for (char ch : x.toCharArray()) if (!Character.isDigit(ch)) return "Neither";
        if (Integer.parseInt(x) > 255) return "Neither";
    }
    return "IPv4";
}

Node *first = nullptr, *last = nullptr;
void helper(Node* node) {
    if (!node) return;
    helper(node->left);
    if (last) { last->right = node; node->left = last; }
    else first = node;
    last = node;
    helper(node->right);
}
Node* treeToDoublyList(Node* root) {
    if (!root) return nullptr;
    helper(root);
    last->right = first; first->left = last;
    return first;
}

const decodeString = (s) => {
    let stack = [], currStr = "", currNum = 0;
    for (let char of s) {
        if (char === '[') {
            stack.push(currStr); stack.push(currNum);
            currStr = ""; currNum = 0;
        } else if (char === ']') {
            let num = stack.pop(), prevStr = stack.pop();
            currStr = prevStr + currStr.repeat(num);
        } else if (!isNaN(char)) currNum = currNum * 10 + Number(char);
        else currStr += char;
    }
    return currStr;
};

def exist(board, word):
    R, C = len(board), len(board[0])
    def dfs(r, c, i):
        if i == len(word): return True
        if r<0 or c<0 or r>=R or c>=C or board[r][c] != word[i]: return False
        tmp, board[r][c] = board[r][c], "#"
        res = dfs(r+1,c,i+1) or dfs(r-1,c,i+1) or dfs(r,c+1,i+1) or dfs(r,c-1,i+1)
        board[r][c] = tmp
        return res
    return any(dfs(r, c, 0) for r in range(R) for c in range(C))

std::vector<int> findClosestElements(std::vector<int>& arr, int k, int x) {
    int l = 0, r = arr.size() - k;
    while (l < r) {
        int mid = (l + r) / 2;
        if (x - arr[mid] > arr[mid + k] - x) l = mid + 1;
        else r = mid;
    }
    return std::vector<int>(arr.begin() + l, arr.begin() + l + k);
}

public boolean validPalindrome(String s) {
    int i = 0, j = s.length() - 1;
    while (i < j) {
        if (s.charAt(i) != s.charAt(j)) return isPal(s, i + 1, j) || isPal(s, i, j - 1);
        i++; j--;
    }
    return true;
}
private boolean isPal(String s, int i, int j) {
    while (i < j) if (s.charAt(i++) != s.charAt(j--)) return false;
    return true;
}

