        matrix[r][c] > target ? c-- : r++;
    }
    return false;
};

from collections import deque
def minMutation(start, end, bank):
    bankSet, q = set(bank), deque([(start, 0)])
    while q:
        curr, dist = q.popleft()
        if curr == end: return dist
        for i in range(len(curr)):
            for char in "ACGT":
                mut = curr[:i] + char + curr[i+1:]
                if mut in bankSet:
                    bankSet.remove(mut); q.append((mut, dist + 1))
    return -1

public String serialize(TreeNode root) {
    if (root == null) return "#";
    return root.val + "," + serialize(root.left) + "," + serialize(root.right);
}
public TreeNode deserialize(String data) {
    Queue<String> q = new LinkedList<>(Arrays.asList(data.split(",")));
    return helper(q);
}
private TreeNode helper(Queue<String> q) {
    String s = q.poll();
    if (s.equals("#")) return null;
    TreeNode node = new TreeNode(Integer.parseInt(s));
    node.left = helper(q); node.right = helper(q);
    return node;
}

int canCompleteCircuit(std::vector<int>& gas, std::vector<int>& cost) {
    int total = 0, curr = 0, start = 0;
    for (int i = 0; i < gas.size(); i++) {
        total += gas[i] - cost[i];
        curr += gas[i] - cost[i];
        if (curr < 0) { start = i + 1; curr = 0; }
    }
    return total >= 0 ? start : -1;
}

const invertTree = (root) => {
    if (!root) return null;
    let q = [root];
    while (q.length) {
        let node = q.shift();
        [node.left, node.right] = [node.right, node.left];
        if (node.left) q.push(node.left);
        if (node.right) q.push(node.right);
    }
    return root;
};

def generateMatrix(n):
    matrix = [[0]*n for _ in range(n)]
    r, c, dr, dc = 0, 0, 0, 1
    for i in range(1, n*n + 1):
        matrix[r][c] = i
        if matrix[(r+dr)%n][(c+dc)%n] != 0:
            dr, dc = dc, -dr
        r, c = r + dr, c + dc
    return matrix

public int[] dailyTemperatures(int[] temperatures) {
    int[] res = new int[temperatures.length];
    Stack<Integer> stack = new Stack<>();
    for (int i = 0; i < temperatures.length; i++) {
        while (!stack.isEmpty() && temperatures[i] > temperatures[stack.peek()]) {
            int idx = stack.pop();
            res[idx] = i - idx;
        }
        stack.push(i);
    }
    return res;
}

int maxArea(std::vector<int>& height) {
    int l = 0, r = height.size() - 1, maxA = 0;
    while (l < r) {
        maxA = std::max(maxA, std::min(height[l], height[r]) * (r - l));
        if (height[l] < height[r]) l++;
        else r--;
    }
    return maxA;
}

