import heapq
def mergeKLists(lists):
    h = []
    for i, lst in enumerate(lists):
        if lst: heapq.heappush(h, (lst.val, i, lst))
    dummy = ListNode(0)
    curr = dummy
    while h:
        val, i, node = heapq.heappop(h)
        curr.next = node
        curr = curr.next
        if node.next: heapq.heappush(h, (node.next.val, i, node.next))
    return dummy.next

public List<List<Integer>> permute(int[] nums) {
    List<List<Integer>> res = new ArrayList<>();
    backtrack(res, new ArrayList<>(), nums);
    return res;
}
private void backtrack(List<List<Integer>> res, List<Integer> tmp, int[] nums) {
    if (tmp.size() == nums.length) res.add(new ArrayList<>(tmp));
    else {
        for (int i = 0; i < nums.length; i++) {
            if (tmp.contains(nums[i])) continue;
            tmp.add(nums[i]); backtrack(res, tmp, nums);
            tmp.remove(tmp.size() - 1);
        }
    }
}

int search(std::vector<int>& nums, int target) {
    int l = 0, r = nums.size() - 1;
    while (l <= r) {
        int mid = l + (r - l) / 2;
        if (nums[mid] == target) return mid;
        if (nums[l] <= nums[mid]) {
            if (target >= nums[l] && target < nums[mid]) r = mid - 1;
            else l = mid + 1;
        } else {
            if (target > nums[mid] && target <= nums[r]) l = mid + 1;
            else r = mid - 1;
        }
    }
    return -1;
}

const merge = (intervals) => {
    if (intervals.length <= 1) return intervals;
    intervals.sort((a, b) => a[0] - b[0]);
    let res = [intervals[0]];
    for (let i = 1; i < intervals.length; i++) {
        if (intervals[i][0] <= res[res.length - 1][1])
            res[res.length - 1][1] = Math.max(res[res.length - 1][1], intervals[i][1]);
        else res.push(intervals[i]);
    }
    return res;
};

