TreeNode* lowestCommonAncestor(TreeNode* root, TreeNode* p, TreeNode* q) {
    while (root) {
        if (p->val < root->val && q->val < root->val) root = root->left;
        else if (p->val > root->val && q->val > root->val) root = root->right;
        else return root;
    }
    return nullptr;
}

const isValidBST = (root, min = null, max = null) => {
    if (!root) return true;
    if (min !== null && root.val <= min) return false;
    if (max !== null && root.val >= max) return false;
    return isValidBST(root.left, min, root.val) && isValidBST(root.right, root.val, max);
};

from collections import deque
def zigzagLevelOrder(root):
    if not root: return []
    res, q, reverse = [], deque([root]), False
    while q:
        level = deque()
        for _ in range(len(q)):
            node = q.popleft()
            if reverse: level.appendleft(node.val)
            else: level.append(node.val)
            if node.left: q.append(node.left)
            if node.right: q.append(node.right)
        res.append(list(level)); reverse = not reverse
    return res

public boolean wordBreak(String s, List<String> wordDict) {
    Set<String> set = new HashSet<>(wordDict);
    boolean[] dp = new boolean[s.length() + 1];
    dp[0] = true;
    for (int i = 1; i <= s.length(); i++) {
        for (int j = 0; j < i; j++) {
            if (dp[j] && set.contains(s.substring(j, i))) {
                dp[i] = true; break;
            }
        }
    }
    return dp[s.length()];
}

std::unordered_map<Node*, Node*> visited;
Node* cloneGraph(Node* node) {
    if (!node) return nullptr;
    if (visited.count(node)) return visited[node];
    Node* clone = new Node(node->val);
    visited[node] = clone;
    for (Node* neighbor : node->neighbors) clone->neighbors.push_back(cloneGraph(neighbor));
    return clone;
}

const kthSmallest = (root, k) => {
    let stack = [];
    while (true) {
        while (root) { stack.push(root); root = root.left; }
        root = stack.pop();
        if (--k === 0) return root.val;
        root = root.right;
    }
};

from collections import OrderedDict
class LRUCache(OrderedDict):
    def __init__(self, capacity: int):
        self.capacity = capacity
    def get(self, key: int) -> int:
        if key not in self: return -1
        self.move_to_end(key)
        return self[key]
    def put(self, key: int, value: int) -> None:
        if key in self: self.move_to_end(key)
        self[key] = value
        if len(self) > self.capacity: self.popitem(last=False)

public int longestConsecutive(int[] nums) {
    Set<Integer> set = new HashSet<>();
    for (int n : nums) set.add(n);
    int res = 0;
    for (int n : set) {
        if (!set.contains(n - 1)) {
            int curr = n, streak = 1;
            while (set.contains(curr + 1)) { curr++; streak++; }
            res = Math.max(res, streak);
        }
    }
    return res;
}

