    for v, u in prerequisites: adj[u].append(v)
    vis = [0] * numCourses
    def hasCycle(u):
        if vis[u] == 1: return True
        if vis[u] == 2: return False
        vis[u] = 1
        for v in adj[u]:
            if hasCycle(v): return True
        vis[u] = 2; return False
    return all(not hasCycle(i) for i in range(numCourses))

