def findWords(board, words):
    trie = {}
    for w in words:
        node = trie
        for c in w: node = node.setdefault(c, {})
        node['#'] = w
    res = []
    def dfs(r, c, node):
        char = board[r][c]
        curr = node[char]
        word = curr.pop('#', None)
        if word: res.append(word)
        board[r][c] = '*'
        for dr, dc in [(0,1),(0,-1),(1,0),(-1,0)]:
            nr, nc = r+dr, c+dc
            if 0<=nr<len(board) and 0<=nc<len(board[0]) and board[nr][nc] in curr:
                dfs(nr, nc, curr)
        board[r][c] = char
        if not curr: node.pop(char)
    for r in range(len(board)):
        for c in range(len(board[0])):
            if board[r][c] in trie: dfs(r, c, trie)
    return res

public List<List<Integer>> permute(int[] nums) {
