    int max_f = freq[25] - 1, idle = max_f * n;
    for (int i = 24; i >= 0 && freq[i] > 0; i--) idle -= std::min(freq[i], max_f);
    return idle > 0 ? idle + tasks.size() : tasks.size();
}

const orangesRotting = (grid) => {
    let q = [], fresh = 0, time = 0;
    for (let r = 0; r < grid.length; r++) {
        for (let c = 0; c < grid[0].length; c++) {
            if (grid[r][c] === 2) q.push([r, c]);
            if (grid[r][c] === 1) fresh++;
        }
    }
    while (q.length && fresh) {
        let nextQ = [];
        for (let [r, c] of q) {
            for (let [dr, dc] of [[0,1],[0,-1],[1,0],[-1,0]]) {
                let nr = r + dr, nc = c + dc;
                if (grid[nr] && grid[nr][nc] === 1) {
                    grid[nr][nc] = 2; fresh--; nextQ.push([nr, nc]);
                }
            }
        }
        q = nextQ; time++;
    }
    return fresh === 0 ? time : -1;
};

def findOrder(numCourses, prerequisites):
    adj = [[] for _ in range(numCourses)]
    indegree = [0] * numCourses
    for v, u in prerequisites: adj[u].append(v); indegree[v] += 1
    q = deque([i for i in range(numCourses) if indegree[i] == 0])
    res = []
    while q:
        u = q.popleft(); res.append(u)
        for v in adj[u]:
            indegree[v] -= 1
            if indegree[v] == 0: q.append(v)
    return res if len(res) == numCourses else []

