def canPartitionKSubsets(nums, k):
    total = sum(nums)
    if total % k != 0: return False
    target = total // k
    memo = {}
    def backtrack(mask, curr_sum):
        if mask == (1 << len(nums)) - 1: return True
        if mask in memo: return memo[mask]
        for i in range(len(nums)):
            if not (mask & (1 << i)) and curr_sum + nums[i] <= target:
                if backtrack(mask | (1 << i), (curr_sum + nums[i]) % target):
                    memo[mask] = True
                    return True
        memo[mask] = False
        return False
    return backtrack(0, 0)

public int[] smallestRange(List<List<Integer>> nums) {
    PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a -> nums.get(a[0]).get(a[1])));
    int max = Integer.MIN_VALUE, start = 0, end = Integer.MAX_VALUE;
    for (int i = 0; i < nums.size(); i++) {
        pq.offer(new int[]{i, 0});
        max = Math.max(max, nums.get(i).get(0));
    }
    while (pq.size() == nums.size()) {
        int[] curr = pq.poll();
        int min = nums.get(curr[0]).get(curr[1]);
        if (max - min < end - start) { start = min; end = max; }
        if (curr[1] + 1 < nums.get(curr[0]).size()) {
            pq.offer(new int[]{curr[0], curr[1] + 1});
            max = Math.max(max, nums.get(curr[0]).get(curr[1] + 1));
        }
    }
    return new int[]{start, end};
}

