void dfs(int u, int& timer, std::vector<int> adj[], std::vector<int>& tin, std::vector<int>& low, std::stack<int>& st, std::vector<bool>& onStack) {
    tin[u] = low[u] = ++timer;
    st.push(u); onStack[u] = true;
    for (int v : adj[u]) {
        if (!tin[v]) {
            dfs(v, timer, adj, tin, low, st, onStack);
            low[u] = std::min(low[u], low[v]);
        } else if (onStack[v]) low[u] = std::min(low[u], tin[v]);
    }
    if (low[u] == tin[u]) {
        while (true) {
            int v = st.top(); st.pop(); onStack[v] = false;
            if (u == v) break;
        }
    }
}

const characterReplacement = (s, k) => {
    let left = 0, maxFreq = 0, res = 0, count = {};
    for (let right = 0; right < s.length; right++) {
        count[s[right]] = (count[s[right]] || 0) + 1;
        maxFreq = Math.max(maxFreq, count[s[right]]);
        if ((right - left + 1) - maxFreq > k) {
            count[s[left]]--;
            left++;
        }
        res = Math.max(res, right - left + 1);
    }
    return res;
};

import heapq
def mincostToHireWorkers(quality, wage, k):
    workers = sorted([w/q, q] for q, w in zip(quality, wage))
    res = float('inf'); q_sum = 0; heap = []
    for ratio, q in workers:
        heapq.heappush(heap, -q)
        q_sum += q
        if len(heap) > k: q_sum += heapq.heappop(heap)
        if len(heap) == k: res = min(res, ratio * q_sum)
    return res

