    while (low < high) {
        int mid = (low + high) / 2, count = 0, left = 0;
        for (int right = 0; right < nums.size(); right++) {
            while (nums[right] - nums[left] > mid) left++;
            count += right - left;
        }
        if (count < k) low = mid + 1; else high = mid;
    }
    return low;
}

