from collections import deque
def shortestPathLength(graph):
    n = len(graph); target = (1 << n) - 1
    q = deque([(i, 1 << i, 0) for i in range(n)])
    visited = {(i, 1 << i) for i in range(n)}
    while q:
        u, mask, dist = q.popleft()
        if mask == target: return dist
        for v in graph[u]:
            if (v, mask | (1 << v)) not in visited:
                visited.add((v, mask | (1 << v)))
                q.append((v, mask | (1 << v), dist + 1))

class MedianWindow {
    PriorityQueue<Integer> min = new PriorityQueue<>(), max = new PriorityQueue<>(Collections.reverseOrder());
    public double[] medianSlidingWindow(int[] nums, int k) {
        double[] res = new double[nums.length - k + 1];
        for (int i = 0; i < nums.length; i++) {
            add(nums[i]);
            if (i >= k) remove(nums[i - k]);
            if (i >= k - 1) res[i - k + 1] = getMedian();
        }
        return res;
    }
    private void add(int n) { max.add(n); min.add(max.poll()); if (min.size() > max.size()) max.add(min.poll()); }
    private void remove(int n) { if (max.contains(n)) max.remove(n); else min.remove(n); }
    private double getMedian() { return max.size() > min.size() ? max.peek() : (max.peek() / 2.0 + min.peek() / 2.0); }
}

