private boolean solve(char[][] board) {
    for (int r = 0; r < 9; r++) {
        for (int c = 0; c < 9; c++) {
            if (board[r][c] == '.') {
                for (char v = '1'; v <= '9'; v++) {
                    if (isValid(board, r, c, v)) {
                        board[r][c] = v;
                        if (solve(board)) return true;
                        board[r][c] = '.';
                    }
                }
                return false;
            }
        }
    }
    return true;
}
private boolean isValid(char[][] b, int r, int c, char v) {
    for (int i = 0; i < 9; i++) {
        if (b[r][i] == v || b[i][c] == v || b[3*(r/3)+i/3][3*(c/3)+i%3] == v) return false;
    }
    return true;
}

bool isMatch(std::string s, std::string p) {
    int m = s.size(), n = p.size();
    std::vector<std::vector<bool>> dp(m + 1, std::vector<bool>(n + 1, false));
    dp[0][0] = true;
    for (int j = 2; j <= n; j++) if (p[j-1] == '*') dp[0][j] = dp[0][j-2];
    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            if (p[j-1] == '*') dp[i][j] = dp[i][j-2] || (dp[i-1][j] && (s[i-1] == p[j-2] || p[j-2] == '.'));
            else dp[i][j] = dp[i-1][j-1] && (s[i-1] == p[j-1] || p[j-1] == '.');
        }
    }
    return dp[m][n];
}

