def trapRainWater(grid):
    R, C = len(grid), len(grid[0]); vis = [[False]*C for _ in range(R)]; pq = []
    for r in range(R):
        for c in range(C):
            if r in {0, R-1} or c in {0, C-1}:
                heapq.heappush(pq, (grid[r][c], r, c)); vis[r][c] = True
    res = 0; dirs = [(0,1),(0,-1),(1,0),(-1,0)]
    while pq:
        h, r, c = heapq.heappop(pq)
        for dr, dc in dirs:
            nr, nc = r+dr, c+dc
            if 0<=nr<R and 0<=nc<C and not vis[nr][nc]:
                res += max(0, h - grid[nr][nc])
                heapq.heappush(pq, (max(h, grid[nr][nc]), nr, nc)); vis[nr][nc] = True
    return res

public List<String> addOperators(String num, int target) {
    List<String> res = new ArrayList<>();
    backtrack(res, "", num, target, 0, 0, 0);
    return res;
}
private void backtrack(List<String> res, String path, String num, int target, int pos, long val, long prev) {
    if (pos == num.length()) {
        if (val == target) res.add(path);
        return;
    }
    for (int i = pos; i < num.length(); i++) {
        if (i != pos && num.charAt(pos) == '0') break;
        long curr = Long.parseLong(num.substring(pos, i + 1));
        if (pos == 0) backtrack(res, "" + curr, num, target, i + 1, curr, curr);
        else {
            backtrack(res, path + "+" + curr, num, target, i + 1, val + curr, curr);
            backtrack(res, path + "-" + curr, num, target, i + 1, val - curr, -curr);
            backtrack(res, path + "*" + curr, num, target, i + 1, val - prev + prev * curr, prev * curr);
        }
    }
}

