def longestIncreasingPath(matrix):
    R, C = len(matrix), len(matrix[0]); memo = {}
    def dfs(r, c):
        if (r, c) in memo: return memo[(r, c)]
        res = 1
        for dr, dc in [(0,1),(0,-1),(1,0),(-1,0)]:
            nr, nc = r+dr, c+dc
            if 0<=nr<R and 0<=nc<C and matrix[nr][nc] > matrix[r][c]:
                res = max(res, 1 + dfs(nr, nc))
        memo[(r, c)] = res
        return res
    return max(dfs(r, c) for r in range(R) for c in range(C))

public String alienOrder(String[] words) {
    Map<Character, Set<Character>> adj = new HashMap<>();
    int[] in = new int[26]; Arrays.fill(in, -1);
    for (String w : words) for (char c : w.toCharArray()) in[c-'a'] = 0;
    for (int i = 0; i < words.length - 1; i++) {
        String w1 = words[i], w2 = words[i+1];
        if (w1.length() > w2.length() && w1.startsWith(w2)) return "";
        for (int j = 0; j < Math.min(w1.length(), w2.length()); j++) {
            char c1 = w1.charAt(j), c2 = w2.charAt(j);
            if (c1 != c2) {
                if (!adj.computeIfAbsent(c1, k -> new HashSet<>()).contains(c2)) {
                    adj.get(c1).add(c2); in[c2-'a']++;
                } break;
            }
        }
    }
    Queue<Character> q = new LinkedList<>();
    for (int i = 0; i < 26; i++) if (in[i] == 0) q.offer((char)(i+'a'));
    StringBuilder sb = new StringBuilder();
    while (!q.isEmpty()) {
        char u = q.poll(); sb.append(u);
        if (adj.containsKey(u)) {
            for (char v : adj.get(u)) if (--in[v-'a'] == 0) q.offer(v);
        }
    }
    int count = 0; for (int i : in) if (i >= 0) count++;
    return sb.length() == count ? sb.toString() : "";
}

std::vector<int> shortestAlternatingPaths(int n, std::vector<std::vector<int>>& red, std::vector<std::vector<int>>& blue) {
    std::vector<std::pair<int, int>> adj[n];
    for (auto& e : red) adj[e[0]].push_back({e[1], 0});
    for (auto& e : blue) adj[e[0]].push_back({e[1], 1});
    std::vector<int> res(n, -1), dist[2] = {std::vector<int>(n, -1), std::vector<int>(n, -1)};
    std::queue<std::pair<int, int>> q; q.push({0, 0}); q.push({0, 1});
    dist[0][0] = dist[1][0] = 0;
    while (!q.empty()) {
        auto [u, color] = q.front(); q.pop();
        for (auto& [v, n_color] : adj[u]) {
            if (n_color != color && dist[n_color][v] == -1) {
                dist[n_color][v] = dist[color][u] + 1;
                q.push({v, n_color});
            }
        }
    }
    for (int i = 0; i < n; i++) {
        if (dist[0][i] != -1 && dist[1][i] != -1) res[i] = std::min(dist[0][i], dist[1][i]);
        else res[i] = std::max(dist[0][i], dist[1][i]);
    }
    return res;
}

