    for (int i = 1; i <= R; i++) {
        for (int j = 1; j <= C; j++) {
            if (matrix[i-1][j-1] == '1') {
                dp[i][j] = std::min({dp[i-1][j], dp[i][j-1], dp[i-1][j-1]}) + 1;
