    while (!q.empty()) {
        Node* u = q.front(); q.pop();
        for (Node* v : u->neighbors) {
            if (!map.count(v)) { map[v] = new Node(v->val); q.push(v); }
            map[u]->neighbors.push_back(map[v]);
        }
    }
    return map[node];
}

