def findOrder(n, pre):
    adj = [[] for _ in range(n)]; in_deg = [0] * n
    for v, u in pre: adj[u].append(v); in_deg[v] += 1
    q = collections.deque([i for i in range(n) if in_deg[i] == 0]); res = []
    while q:
        u = q.popleft(); res.append(u)
        for v in adj[u]:
            in_deg[v] -= 1
            if in_deg[v] == 0: q.append(v)
    return res if len(res) == n else []

