    res, q, rev = [], collections.deque([root]), False
    while q:
        level = collections.deque()
        for _ in range(len(q)):
            n = q.popleft()
            if rev: level.appendleft(n.val)
            else: level.append(n.val)
            if n.left: q.append(n.left)
