def longestPath(matrix):
    if not matrix or not matrix[0]: return 0
    R, C = len(matrix), len(matrix[0])
    memo = {}
    def dfs(r, c):
        if (r, c) in memo: return memo[(r, c)]
        res = 1
        for dr, dc in [(0,1),(0,-1),(1,0),(-1,0)]:
            nr, nc = r + dr, c + dc
            if 0 <= nr < R and 0 <= nc < C and matrix[nr][nc] == 0:
                # Avoid cycles by treating current as wall temporarily in a standard DFS
                # but for DAG/Path problems, simple memoization works if no cycles exist
                res = max(res, 1 + dfs(nr, nc))
        memo[(r, c)] = res
        return res
    # Example logic assumes a Directed Acyclic context or specific movement rules
    return max(dfs(r, c) for r in range(R) for c in range(C) if matrix[r][c] == 0)

import java.util.LinkedList;
import java.util.concurrent.locks.ReentrantLock;

public class ThreadSafeStack<T> {
    private LinkedList<T> list = new LinkedList<>();
    private ReentrantLock lock = new ReentrantLock();

    public void push(T item) {
        lock.lock();
        try { list.addFirst(item); }
        finally { lock.unlock(); }
    }

    public T pop() {
        lock.lock();
        try { return list.isEmpty() ? null : list.removeFirst(); }
        finally { lock.unlock(); }
    }
}

int maxCoins(std::vector<int>& nums) {
    int n = nums.size();
    std::vector<int> vals(n + 2, 1);
    for (int i = 0; i < n; i++) vals[i + 1] = nums[i];
    std::vector<std::vector<int>> dp(n + 2, std::vector<int>(n + 2, 0));
    for (int len = 1; len <= n; len++) {
        for (int i = 1; i <= n - len + 1; i++) {
            int j = i + len - 1;
            for (int k = i; k <= j; k++) {
                dp[i][j] = std::max(dp[i][j], vals[i - 1] * vals[k] * vals[j + 1] + dp[i][k - 1] + dp[k + 1][j]);
            }
        }
    }
    return dp[1][n];
}

