def canFinish(n, pre):
    adj = [[] for _ in range(n)]; in_deg = [0] * n
    for v, u in pre: adj[u].append(v); in_deg[v] += 1
    q = deque([i for i in range(n) if in_deg[i] == 0])
    count = 0
    while q:
        u = q.popleft(); count += 1
        for v in adj[u]:
            in_deg[v] -= 1
            if in_deg[v] == 0: q.append(v)
    return count == n

