const zigzagLevelOrder = (root) => {
    if (!root) return [];
    let res = [], q = [root], rev = false;
    while (q.length) {
        let level = [], size = q.length;
        for (let i = 0; i < size; i++) {
            let n = q.shift(); rev ? level.unshift(n.val) : level.push(n.val);
            if (n.left) q.push(n.left); if (n.right) q.push(n.right);
        } res.add(level); rev = !rev;
    } return res;
};

public int search(int[] nums, int target) {
    int l = 0, r = nums.length - 1;
    while (l <= r) {
        int m = l + (r - l) / 2;
        if (nums[m] == target) return m;
        if (nums[l] <= nums[m]) {
            if (target >= nums[l] && target < nums[m]) r = m - 1; else l = m + 1;
        } else {
            if (target > nums[m] && target <= nums[r]) l = m + 1; else r = m - 1;
        }
    } return -1;
}

