public boolean isValidSudoku(char[][] board) {
    for (int i = 0; i < 9; i++) {
        boolean[] row = new boolean[9], col = new boolean[9], box = new boolean[9];
        for (int j = 0; j < 9; j++) {
            if (board[i][j] != '.') {
                int num = board[i][j] - '1';
                if (row[num]) return false; row[num] = true;
            }
            if (board[j][i] != '.') {
                int num = board[j][i] - '1';
                if (col[num]) return false; col[num] = true;
            }
            int r = 3 * (i / 3) + j / 3, c = 3 * (i % 3) + j % 3;
            if (board[r][c] != '.') {
                int num = board[r][c] - '1';
                if (box[num]) return false; box[num] = true;
            }
        }
    }
    return true;
}

