def minWindow(s1, s2):
    m, n = len(s1), len(s2)
    dp = [[-1] * (n + 1) for _ in range(m + 1)]
    for i in range(m + 1): dp[i][0] = i
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if s1[i-1] == s2[j-1]: dp[i][j] = dp[i-1][j-1]
            else: dp[i][j] = dp[i-1][j]
    start, length = 0, float('inf')
    for i in range(1, m + 1):
        if dp[i][n] != -1:
            if i - dp[i][n] < length:
