public int maximalRectangle(char[][] matrix) {
    if (matrix.length == 0) return 0;
    int[] h = new int[matrix[0].length];
    int res = 0;
    for (char[] row : matrix) {
        for (int i = 0; i < row.length; i++) h[i] = row[i] == '1' ? h[i] + 1 : 0;
        res = Math.max(res, largestHist(h));
