private int largestHist(int[] h) {
    Stack<Integer> st = new Stack<>(); st.push(-1);
    int max = 0;
    for (int i = 0; i < h.length; i++) {
        while (st.peek() != -1 && h[st.peek()] >= h[i]) max = Math.max(max, h[st.pop()] * (i - st.peek() - 1));
        st.push(i);
    }
    while (st.peek() != -1) max = Math.max(max, h[st.pop()] * (h.length - st.peek() - 1));
    return max;
}

