    for v, u in pre: adj[u].append(v)
    def cycle(u):
        if vis[u] == 1: return True
        if vis[u] == 2: return False
        vis[u] = 1
        for v in adj[u]:
            if cycle(v): return True
        vis[u] = 2; return False
    return all(not cycle(i) for i in range(n))

