        int size = q.size(); List<Integer> level = new ArrayList<>();
        for (int i = 0; i < size; i++) {
            TreeNode n = q.poll(); level.add(n.val);
            if (n.left != null) q.add(n.left); if (n.right != null) q.add(n.right);
        } res.add(level);
    }
    return res;
}

int trap(std::vector<int>& h) {
    int l = 0, r = h.size() - 1, lM = 0, rM = 0, res = 0;
    while (l < r) {
        if (h[l] < h[r]) { if (h[l] >= lM) lM = h[l]; else res += lM - h[l]; l++; }
        else { if (h[r] >= rM) rM = h[r]; else res += rM - h[r]; r--; }
    }
    return res;
}

