    for (int i=0; i<n; i++) adj[i] = new ArrayList<>();
    for (int[] p : pre) { adj[p[1]].add(p[0]); in[p[0]]++; }
    Queue<Integer> q = new LinkedList<>(); for (int i=0; i<n; i++) if (in[i] == 0) q.add(i);
    int[] res = new int[n]; int idx = 0;
    while (!q.isEmpty()) {
        int u = q.poll(); res[idx++] = u;
        for (int v : adj[u]) if (--in[v] == 0) q.add(v);
    }
    return idx == n ? res : new int[0];
}

