bool isBipartite(int n, std::vector<int> adj[]) {
    std::vector<int> color(n, -1); // -1: uncolored, 0: color A, 1: color B
    for (int i = 0; i < n; i++) {
        if (color[i] == -1) {
            std::queue<int> q;
            q.push(i); color[i] = 0;
            while (!q.empty()) {
                int u = q.front(); q.pop();
                for (int v : adj[u]) {
                    if (color[v] == -1) {
                        color[v] = 1 - color[u];
                        q.push(v);
                    } else if (color[v] == color[u]) return false;
                }
            }
        }
    }
    return true;
}

function totalNQueens(n) {
    let count = 0;
    const cols = new Set(), diag1 = new Set(), diag2 = new Set();

    function backtrack(row) {
        if (row === n) { count++; return; }
        for (let col = 0; col < n; col++) {
            if (cols.has(col) || diag1.has(row - col) || diag2.has(row + col)) continue;
            cols.add(col); diag1.add(row - col); diag2.add(row + col);
            backtrack(row + 1);
            cols.delete(col); diag1.delete(row - col); diag2.delete(row + col);
        }
    }
    backtrack(0);
    return count;
}

def findArticulationPoints(n, adj):
    tin, low = [-1] * n, [-1] * n
    timer, points = 0, set()

    def dfs(u, p=-1):
        nonlocal timer
        tin[u] = low[u] = timer; timer += 1
        children = 0
        for v in adj[u]:
            if v == p: continue
            if tin[v] != -1: low[u] = min(low[u], tin[v])
            else:
                dfs(v, u)
                low[u] = min(low[u], low[v])
                if low[v] >= tin[u] and p != -1: points.add(u)
                children += 1
        if p == -1 and children > 1: points.add(u)

    for i in range(n): 
        if tin[i] == -1: dfs(i)
    return list(points)

