std::vector<int> kmpSearch(std::string text, std::string pat) {
    int n = text.size(), m = pat.size();
    std::vector<int> lps(m, 0), res;
    for (int i = 1, j = 0; i < m; i++) {
        while (j > 0 && pat[i] != pat[j]) j = lps[j-1];
        if (pat[i] == pat[j]) lps[i] = ++j;
    }
    for (int i = 0, j = 0; i < n; i++) {
        while (j > 0 && text[i] != pat[j]) j = lps[j-1];
        if (text[i] == pat[j]) j++;
        if (j == m) { res.push_back(i - m + 1); j = lps[j-1]; }
    }
    return res;
}

