            if board[i][c] == k or board[r][i] == k: return False
            if board[3*(r//3)+i//3][3*(c//3)+i%3] == k: return False
        return True

    for r in range(9):
        for c in range(9):
            if board[r][c] == '.':
                for k in '123456789':
                    if is_valid(r, c, k):
