class FreqStack {
    constructor() { this.freq = {}; this.group = {}; this.maxf = 0; }
    push(x) {
        let f = (this.freq[x] || 0) + 1; this.freq[x] = f;
        if (f > this.maxf) this.maxf = f;
        if (!this.group[f]) this.group[f] = [];
        this.group[f].push(x);
    }
    pop() {
        let x = this.group[this.maxf].pop();
        this.freq[x]--;
        if (!this.group[this.maxf].length) this.maxf--;
        return x;
    }
}

def exist(board, word):
    R, C = len(board), len(board[0])
    def dfs(r, c, i):
        if i == len(word): return True
        if r<0 or r>=R or c<0 or c>=C or board[r][c] != word[i]: return False
        tmp, board[r][c] = board[r][c], "#"
        res = dfs(r+1,c,i+1) or dfs(r-1,c,i+1) or dfs(r,c+1,i+1) or dfs(r,c-1,i+1)
        board[r][c] = tmp
        return res
    return any(dfs(r, c, 0) for r in range(R) for c in range(C))

public List<Integer> spiralOrder(int[][] matrix) {
    List<Integer> res = new ArrayList<>();
    int r1 = 0, r2 = matrix.length-1, c1 = 0, c2 = matrix[0].length-1;
    while (r1 <= r2 && c1 <= c2) {
        for (int i=c1; i<=c2; i++) res.add(matrix[r1][i]);
        for (int i=r1+1; i<=r2; i++) res.add(matrix[i][c2]);
        if (r1 < r2 && c1 < c2) {
            for (int i=c2-1; i>c1; i--) res.add(matrix[r2][i]);
            for (int i=r2; i>r1; i--) res.add(matrix[i][c1]);
        }
        r1++; r2--; c1++; c2--;
    }
    return res;
}

int orangesRotting(std::vector<std::vector<int>>& grid) {
    int R = grid.size(), C = grid[0].size(), fresh = 0, time = 0;
    std::queue<std::pair<int, int>> q;
    for (int r=0; r<R; r++) for (int c=0; c<C; c++) {
        if (grid[r][c] == 2) q.push({r, c});
        if (grid[r][c] == 1) fresh++;
    }
    int dr[] = {0,0,1,-1}, dc[] = {1,-1,0,0};
    while (!q.empty() && fresh > 0) {
        int size = q.size();
        while (size--) {
            auto [r, c] = q.front(); q.pop();
            for (int i=0; i<4; i++) {
                int nr = r+dr[i], nc = c+dc[i];
                if (nr>=0 && nr<R && nc>=0 && nc<C && grid[nr][nc] == 1) {
                    grid[nr][nc] = 2; fresh--; q.push({nr, nc});
                }
            }
        } time++;
    }
    return fresh == 0 ? time : -1;
}

