std::vector<int> distanceK(TreeNode* root, TreeNode* target, int k) {
    findPar(root, nullptr);
    std::queue<TreeNode*> q; q.push(target);
    std::unordered_map<TreeNode*, bool> vis; vis[target] = true;
    int dist = 0;
    while (!q.empty()) {
        if (dist++ == k) break;
        int size = q.size();
        while (size--) {
            TreeNode* u = q.front(); q.pop();
            TreeNode* neighbors[] = {u->left, u->right, parent[u]};
            for (auto v : neighbors) if (v && !vis[v]) { vis[v] = true; q.push(v); }
        }
    }
    std::vector<int> res; while (!q.empty()) { res.push_back(q.front()->val); q.pop(); }
    return res;
}

