    function dfs(u) {
        if (vis[u] === 1) return true;
        if (vis[u] === 2) return false;
        vis[u] = 1;
        for (let v of adj[u]) if (dfs(v)) return true;
        vis[u] = 2; return false;
    }
    for (let i = 0; i < n; i++) if (dfs(i)) return false;
    return true;
}

