public String alienOrder(String[] words) {
    Map<Character, Set<Character>> adj = new HashMap<>(); int[] in = new int[26];
    Arrays.fill(in, -1); for (String w : words) for (char c : w.toCharArray()) in[c-'a'] = 0;
    for (int i=0; i<words.length-1; i++) {
        String w1 = words[i], w2 = words[i+1];
        if (w1.length() > w2.length() && w1.startsWith(w2)) return "";
        for (int j=0; j<Math.min(w1.length(), w2.length()); j++) {
            char c1 = w1.charAt(j), c2 = w2.charAt(j);
            if (c1 != c2) {
                if (!adj.computeIfAbsent(c1, k -> new HashSet<>()).contains(c2)) { adj.get(c1).add(c2); in[c2-'a']++; }
                break;
            }
        }
    }
    Queue<Character> q = new LinkedList<>(); for (int i=0; i<26; i++) if (in[i] == 0) q.add((char)(i+'a'));
    StringBuilder sb = new StringBuilder(); while (!q.isEmpty()) {
        char u = q.poll(); sb.append(u); 
        if (adj.containsKey(u)) for (char v : adj.get(u)) if (--in[v-'a'] == 0) q.add(v);
    }
    int count = 0; for (int i : in) if (i >= 0) count++;
    return sb.length() == count ? sb.toString() : "";
}

