function canCross(stones) {
    const map = new Map();
    for (let s of stones) map.set(s, new Set());
    map.get(0).add(1);
    for (let s of stones) {
        for (let step of map.get(s)) {
            let next = s + step;
            if (next === stones[stones.length-1]) return true;
            if (map.has(next)) {
                if (step > 1) map.get(next).add(step - 1);
                map.get(next).add(step); map.get(next).add(step + 1);
            }
        }
    } return false;
}

def numDistinctIslands(grid):
