            grid[r][c] = 0; path.append(d)
            dfs(r+1,c,'D'); dfs(r-1,c,'U'); dfs(r,c+1,'R'); dfs(r,c-1,'L')
            path.append('B')
    for r in range(R):
        for c in range(C):
            if grid[r][c]: path = []; dfs(r, c, 'S'); seen.add("".join(path))
    return len(seen)

public List<String> addOperators(String num, int target) {
    List<String> res = new ArrayList<>();
    dfs(0, 0, 0, "", num, target, res);
    return res;
}
private void dfs(int i, long val, long prev, String path, String num, int t, List<String> res) {
    if (i == num.length()) { if (val == t) res.add(path); return; }
    for (int j=i; j<num.length(); j++) {
        if (j > i && num.charAt(i) == '0') break;
        long curr = Long.parseLong(num.substring(i, j+1));
        if (i == 0) dfs(j+1, curr, curr, ""+curr, num, t, res);
        else {
            dfs(j+1, val+curr, curr, path+"+"+curr, num, t, res);
            dfs(j+1, val-curr, -curr, path+"-"+curr, num, t, res);
            dfs(j+1, val-prev+prev*curr, prev*curr, path+"*"+curr, num, t, res);
        }
    }
}

double findMedianSortedArrays(std::vector<int>& n1, std::vector<int>& n2) {
    if (n1.size() > n2.size()) return findMedianSortedArrays(n2, n1);
    int x = n1.size(), y = n2.size(), lo = 0, hi = x;
    while (lo <= hi) {
        int px = (lo+hi)/2, py = (x+y+1)/2 - px;
        int lx = (px == 0) ? INT_MIN : n1[px-1];
        int rx = (px == x) ? INT_MAX : n1[px];
        int ly = (py == 0) ? INT_MIN : n2[py-1];
        int ry = (py == y) ? INT_MAX : n2[py];
        if (lx <= ry && ly <= rx) {
            if ((x+y)%2 == 0) return (std::max(lx, ly) + std::min(rx, ry)) / 2.0;
            else return std::max(lx, ly);
        } else if (lx > ry) hi = px - 1; else lo = px + 1;
    } return 0.0;
}

function verticalTraversal(root) {
    const map = new Map(), q = [[root, 0, 0]];
    while (q.length) {
        const [n, x, y] = q.shift();
        if (!map.has(x)) map.set(x, []);
        map.get(x).push([y, n.val]);
        if (n.left) q.push([n.left, x-1, y+1]);
        if (n.right) q.push([n.right, x+1, y+1]);
    }
    return [...map.keys()].sort((a,b)=>a-b).map(x => map.get(x).sort((a,b)=>a[0]-b[0] || a[1]-b[1]).map(v=>v[1]));
}

