void clean(Robot& robot, int r, int c, int d, std::set<std::pair<int,int>>& vis) {
    robot.clean(); vis.insert({r, c});
    int dr[] = {-1,0,1,0}, dc[] = {0,1,0,-1};
    for (int i=0; i<4; i++) {
        int nd = (d+i)%4, nr = r+dr[nd], nc = c+dc[nd];
        if (!vis.count({nr, nc}) && robot.move()) {
