function trap(height) {
    let l = 0, r = height.length - 1, lM = 0, rM = 0, res = 0;
    while (l < r) {
        if (height[l] < height[r]) {
            height[l] >= lM ? (lM = height[l]) : (res += lM - height[l]);
            l++;
        } else {
            height[r] >= rM ? (rM = height[r]) : (res += rM - height[r]);
            r--;
        }
    } return res;
}

