public int minCut(String s) {
    int n = s.length(); int[] dp = new int[n];
    boolean[][] p = new boolean[n][n];
    for (int i=0; i<n; i++) {
        int min = i;
        for (int j=0; j<=i; j++) {
            if (s.charAt(i) == s.charAt(j) && (i-j<2 || p[j+1][i-1])) {
                p[j][i] = true;
                min = (j == 0) ? 0 : Math.min(min, dp[j-1] + 1);
            }
        } dp[i] = min;
    } return dp[n-1];
}

public List<List<Integer>> levelOrderBottom(TreeNode root) {
    LinkedList<List<Integer>> res = new LinkedList<>();
    if (root == null) return res;
    Queue<TreeNode> q = new LinkedList<>(); q.add(root);
    while (!q.isEmpty()) {
        int size = q.size(); List<Integer> level = new ArrayList<>();
        while (size-- > 0) {
            TreeNode n = q.poll(); level.add(n.val);
            if (n.left != null) q.add(n.left); if (n.right != null) q.add(n.right);
        } res.addFirst(level);
    } return res;
}

