import heapq
def smallestRange(nums):
    pq = [(row[0], i, 0) for i, row in enumerate(nums)]; heapq.heapify(pq)
    right = max(row[0] for row in nums); res = [-1e9, 1e9]
    while len(pq) == len(nums):
        left, i, j = heapq.heappop(pq)
        if right - left < res[1] - res[0]: res = [left, right]
        if j + 1 < len(nums[i]):
            v = nums[i][j+1]; right = max(right, v); heapq.heappush(pq, (v, i, j+1))
    return res

